-- Flow templates: table + seed data for common business types
CREATE TABLE IF NOT EXISTS flow_templates (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  category TEXT NOT NULL,
  business_type TEXT NOT NULL,
  nodes JSONB NOT NULL DEFAULT '[]',
  edges JSONB NOT NULL DEFAULT '[]',
  tags TEXT[],
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMP NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMP NOT NULL DEFAULT NOW()
);

-- Seed flow templates
INSERT INTO flow_templates (name, description, category, business_type, nodes, edges, tags, is_active)
VALUES (
  'Flower Shop Flow',
  'End-to-end WhatsApp flow for flower shops: catalog browsing, custom bouquets, occasion arrangements, delivery options, and media sharing.',
  'Retail',
  'flower_shop',
  $fn$[{"id":"trigger-node-flower","type":"trigger","position":{"x":-317.53423307367075,"y":501.4353816744428},"data":{"label":"Message Trigger","channelTypes":["whatsapp_unofficial"],"conditionType":"any","conditionValue":"","enableSessionPersistence":true,"sessionTimeout":30,"sessionTimeoutUnit":"minutes","targetPosition":"top","sourcePosition":"bottom"},"width":300,"height":135},{"id":"node_ai_flower","type":"ai_assistant","position":{"x":100,"y":480},"data":{"label":"AI Assistant","provider":"openai","model":"gpt-3.5-turbo","prompt":"You are a helpful *florist assistant* for a flower shop. Answer customer queries clearly, politely, and accurately.\n\nYou can help customers with:\n\n* Browsing the flower catalog and seasonal availability\n* Custom bouquet requests and occasion-based arrangements (birthdays, weddings, sympathy, etc.)\n* Flower care tips and delivery options\n* Order tracking and delivery schedules\n* Pricing and promotions\n\nGuidelines:\n\n* Be friendly, knowledgeable about flowers, and professional\n* Keep responses concise and easy to understand\n* Suggest suitable alternatives if a specific flower is out of season or out of stock\n* For custom orders, collect occasion, preferred colors, budget, and delivery date\n* Do not make up flower availability; suggest they check with the shop for current stock\n","enableHistory":true,"enableAudio":false,"enableTaskExecution":true,"tasks":[{"id":"task_flower_video","name":"Share Flower Shop Video","description":"","functionDefinition":{"name":"share_flower_shop_video","description":"Only execute when the user asks for a video about the flower shop, arrangements, or tutorials.","parameters":{"type":"object","properties":{"video_type":{"type":"string","description":"Type of video requested"},"user_request":{"type":"string","description":"The user's request"}},"required":["video_type","user_request"]}},"outputHandle":"task_flower_video","enabled":true},{"id":"task_flower_photo","name":"Share Flower Shop Photo","description":"","functionDefinition":{"name":"share_flower_shop_photo","description":"Trigger when the user asks for an image, photo, or picture of flowers, bouquets, or the shop.","parameters":{"type":"object","properties":{"image_type":{"type":"string","description":"Type of image requested"},"user_request":{"type":"string","description":"The user's request"}},"required":["image_type","user_request"]}},"outputHandle":"task_flower_photo","enabled":true}],"enableGoogleCalendar":false,"credentialSource":"auto","language":"en","historyLimit":5,"enableTextToSpeech":true,"ttsProvider":"openai","ttsVoice":"shimmer","voiceResponseMode":"voice_only","maxAudioDuration":30,"enableSessionTakeover":true,"stopKeyword":"stop","exitOutputHandle":"ai-stopped","knowledgeBaseEnabled":false,"enableMCPServers":false,"mcpServers":[],"_handleKey":1,"targetPosition":"top","sourcePosition":"bottom"},"width":516,"height":176},{"id":"node_video_flower","type":"video","position":{"x":764,"y":221},"data":{"label":"Video Node","mediaUrl":"https://www.youtube.com/shorts/xxsp6PjbAxg?feature=share","caption":"Dear {{contact.name}} Check out our flower shop!","targetPosition":"top","sourcePosition":"bottom"},"width":350,"height":250},{"id":"node_image_flower","type":"image","position":{"x":765,"y":496},"data":{"label":"Image Node","mediaUrl":"https://i.ibb.co/CpBXLNF1/images.jpg","caption":"Dear {{contact.name}} Here's a look at our arrangements!","originalName":"","mimetype":"","size":0},"width":350,"height":330}]$fn$::jsonb,
  $fe$[{"id":"edge-trigger-ai-flower","source":"trigger-node-flower","target":"node_ai_flower","animated":true,"type":"smoothstep"},{"animated":true,"type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_ai_flower","sourceHandle":"task_flower_video","target":"node_video_flower","targetHandle":null,"id":"edge-ai-video-flower"},{"animated":true,"type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_ai_flower","sourceHandle":"task_flower_photo","target":"node_image_flower","targetHandle":null,"id":"edge-ai-image-flower"}]$fe$::jsonb,
  ARRAY['whatsapp', 'retail', 'flower_shop'],
  true
)
ON CONFLICT DO NOTHING;

INSERT INTO flow_templates (name, description, category, business_type, nodes, edges, tags, is_active)
