  'Retail',
  'cloth_shop',
  $cn$[{"id":"trigger-node-cloth","type":"trigger","position":{"x":-317.53423307367075,"y":501.4353816744428},"data":{"label":"Message Trigger","channelTypes":["whatsapp_unofficial"],"conditionType":"any","conditionValue":"","enableSessionPersistence":true,"sessionTimeout":30,"sessionTimeoutUnit":"minutes","targetPosition":"top","sourcePosition":"bottom"},"width":300,"height":135},{"id":"node_ai_cloth","type":"ai_assistant","position":{"x":100,"y":480},"data":{"label":"AI Assistant","provider":"openai","model":"gpt-3.5-turbo","prompt":"You are a helpful *clothing store assistant*. Answer customer queries clearly, politely, and accurately.\n\nYou can help customers with:\n\n* Browsing collections (men's, women's, kids' wear)\n* Size guides and fit advice\n* Styling recommendations and outfit ideas\n* Stock availability and new arrivals\n* Order status and returns\n* Promotions and shipping information\n\nGuidelines:\n\n* Be friendly, fashion-forward, and professional\n* Keep responses concise and easy to understand\n* Suggest alternatives if an item is out of stock\n* For size questions, ask for measurements or refer to our size chart\n* Do not make up product details; suggest they check the catalog or visit the store for specific items\n","enableHistory":true,"enableAudio":false,"enableTaskExecution":true,"tasks":[{"id":"task_cloth_video","name":"Share Store Video","description":"","functionDefinition":{"name":"share_cloth_store_video","description":"Only execute when the user asks for a video about the store, collection, or lookbook.","parameters":{"type":"object","properties":{"video_type":{"type":"string","description":"Type of video requested"},"user_request":{"type":"string","description":"The user's request"}},"required":["video_type","user_request"]}},"outputHandle":"task_cloth_video","enabled":true},{"id":"task_cloth_photo","name":"Share Store Photo","description":"","functionDefinition":{"name":"share_cloth_store_photo","description":"Trigger when the user asks for an image, photo, or picture of the store or collection.","parameters":{"type":"object","properties":{"image_type":{"type":"string","description":"Type of image requested"},"user_request":{"type":"string","description":"The user's request"}},"required":["image_type","user_request"]}},"outputHandle":"task_cloth_photo","enabled":true}],"enableGoogleCalendar":false,"credentialSource":"auto","language":"en","historyLimit":5,"enableTextToSpeech":true,"ttsProvider":"openai","ttsVoice":"shimmer","voiceResponseMode":"voice_only","maxAudioDuration":30,"enableSessionTakeover":true,"stopKeyword":"stop","exitOutputHandle":"ai-stopped","knowledgeBaseEnabled":false,"enableMCPServers":false,"mcpServers":[],"_handleKey":1,"targetPosition":"top","sourcePosition":"bottom"},"width":516,"height":176},{"id":"node_video_cloth","type":"video","position":{"x":764,"y":221},"data":{"label":"Video Node","mediaUrl":"https://www.youtube.com/watch?v=GhH95h6-ClE&pp=ygUWY2xvYXRoIHN0b3JlIGFyZ2VudGluYQ%3D%3D","caption":"Dear {{contact.name}} Check out our latest collection!","targetPosition":"top","sourcePosition":"bottom"},"width":350,"height":250},{"id":"node_image_cloth","type":"image","position":{"x":765,"y":496},"data":{"label":"Image Node","mediaUrl":"https://i.ibb.co/NgVwWCRF/gen1-store-buenosaires.jpg","caption":"Dear {{contact.name}} Here's a look from our store!","originalName":"","mimetype":"","size":0},"width":350,"height":330}]$cn$::jsonb,
