INSERT INTO flow_templates (name, description, category, business_type, nodes, edges, tags, is_active)
VALUES (
  'Dental Clinic Flow',
  'End-to-end WhatsApp flow for dental clinics: appointment booking, dentist availability, rescheduling, clinic info, and media sharing.',
  'Healthcare',
  'dental_clinic',
  $dn$[{"id":"trigger-node","type":"trigger","position":{"x":-317.53423307367075,"y":501.4353816744428},"data":{"label":"Message Trigger","channelTypes":["whatsapp_unofficial"],"conditionType":"any","conditionValue":"","enableSessionPersistence":true,"sessionTimeout":30,"sessionTimeoutUnit":"minutes","targetPosition":"top","sourcePosition":"bottom"},"width":300,"height":135},{"id":"node_G0dncsqmYeR0luHedcn_m","type":"ai_assistant","position":{"x":100,"y":480},"data":{"label":"Ai_assistant Node","provider":"openai","model":"gpt-3.5-turbo","prompt":"You are a helpful *dental clinic assistant*. Answer patient queries clearly, politely, and accurately.\n\nYou can help patients with:\n\n* Booking dental appointments (checkups, cleaning, fillings, root canal, braces, whitening, etc.)\n* Checking dentist availability\n* Rescheduling or updating appointments\n* Cancelling appointments\n* Providing basic information about dental services, clinic timings, and preparation instructions\n\nFor appointment booking:\n\n1. Always check available slots first\n2. Collect required details (patient name, treatment type, date, preferred time, phone number, email)\n3. Ask for any relevant dental concerns if needed\n4. Confirm all details with the patient before booking\n5. Provide a clear confirmation with appointment details\n\nFor rescheduling or cancellation:\n\n* Verify patient identity (email or phone) before making any changes\n* Confirm the requested changes before updating\n\nFor appointment history:\n\n* Always ask for the patient's email or phone number to retrieve previous appointments\n* Only share appointment details with the verified patient\n* Never share information about other patients\n\nGuidelines:\n\n* Be polite, reassuring, and professional in tone\n* Keep responses concise and easy to understand\n* Suggest suitable appointment times if the requested slot is unavailable\n* Remind patients about arriving early if required\n* Do not provide medical diagnosis; for serious concerns, advise visiting the dentist\n\nNote: Always check available slots before responding to appointment requests. For example, if a patient asks for 10 AM on a specific date, verify availability first, then respond accordingly.\n","enableHistory":true,"enableAudio":false,"enableTaskExecution":true,"tasks":[{"id":"task_1771362429898_3612","name":"Share Dental Clinic Video","description":"","functionDefinition":{"name":"share_dental_clinic_video","description":"Only execute this function when the user clearly asks for information about the dental clinic. This is connected to the video node, so when it is executed, it will share the dental clinic video with the contact.","parameters":{"type":"object","properties":{"video_type":{"type":"string","description":"Type of video requested (tutorial, demo, promotional, etc.)"},"user_request":{"type":"string","description":"The user's original request for the video"}},"required":["video_type","user_request"]}},"outputHandle":"task_1771362429898_3612","enabled":true},{"id":"task_1771363045318_9244","name":"Share Dental Clinic Photo","description":"","functionDefinition":{"name":"share_dental_clinic_photo","description":"Trigger this function only when the user asks for an image, screenshot, or picture of the dental clinic. This function's output is connected to an image node that will send an image of the clinic when triggerd.","parameters":{"type":"object","properties":{"image_type":{"type":"string","description":"Type of image requested (screenshot, photo, diagram, etc.)"},"user_request":{"type":"string","description":"The user's original request for the image"}},"required":["image_type","user_request"]}},"outputHandle":"task_1771363045318_9244","enabled":true}],"enableGoogleCalendar":true,"calendarBusinessHours":{"start":"09:00","end":"17:00"},"calendarDefaultDuration":60,"calendarTimeZone":"Asia/Karachi","calendarFunctions":[],"credentialSource":"auto","language":"en","historyLimit":5,"enableTextToSpeech":true,"ttsProvider":"openai","ttsVoice":"shimmer","voiceResponseMode":"voice_only","maxAudioDuration":30,"enableSessionTakeover":true,"stopKeyword":"stop","exitOutputHandle":"ai-stopped","calendarBufferMinutes":0,"calendarAdvancedMode":true,"calendarAdvancedSettings":{"weeklySchedule":[{"dayName":"Sunday","dayIndex":0,"enabled":false,"startTime":"09:00","endTime":"17:00"},{"dayName":"Monday","dayIndex":1,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Tuesday","dayIndex":2,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Wednesday","dayIndex":3,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Thursday","dayIndex":4,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Friday","dayIndex":5,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Saturday","dayIndex":6,"enabled":false,"startTime":"09:00","endTime":"17:00"}],"offDays":[0,6]},"enableZohoCalendar":false,"zohoCalendarBusinessHours":{"start":"09:00","end":"17:00"},"zohoCalendarDefaultDuration":60,"zohoCalendarTimeZone":"Asia/Karachi","zohoCalendarAdvancedMode":true,"zohoCalendarAdvancedSettings":{"weeklySchedule":[{"dayName":"Sunday","dayIndex":0,"enabled":false,"startTime":"09:00","endTime":"17:00"},{"dayName":"Monday","dayIndex":1,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Tuesday","dayIndex":2,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Wednesday","dayIndex":3,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Thursday","dayIndex":4,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Friday","dayIndex":5,"enabled":true,"startTime":"09:00","endTime":"17:00"},{"dayName":"Saturday","dayIndex":6,"enabled":false,"startTime":"09:00","endTime":"17:00"}],"offDays":[0,6]},"zohoCalendarFunctions":[],"knowledgeBaseEnabled":false,"knowledgeBaseConfig":{"maxRetrievedChunks":3,"similarityThreshold":0.7,"contextPosition":"before_system","contextTemplate":"Based on the following knowledge base information:\n\n{context}\n\nPlease answer the user's question using this information when relevant."},"enableMCPServers":false,"pineconeEnvironment":"us-east-1","pineconeIndexName":"","elevenLabsVoiceId":"JaagUurP1dmW3WscoJ79","elevenLabsModel":"eleven_monolingual_v1","elevenLabsStability":0.5,"elevenLabsSimilarityBoost":0.75,"elevenLabsStyle":0,"elevenLabsUseSpeakerBoost":true,"elevenLabsPromptInfluence":0.5,"elevenLabsEnableAudioTags":false,"elevenLabsAudioTagsInstructions":"Use [excited] when discussing features, [whispers] for confidential information, [pause] before important points","mcpServers":[],"_handleKey":1,"targetPosition":"top","sourcePosition":"bottom"},"width":516,"height":176},{"id":"node_-XubJUXAHY9KafiHR_0bd","type":"video","position":{"x":764.3690471617365,"y":221.3412442597442},"data":{"label":"Video Node","mediaUrl":"https://www.youtube.com/shorts/heXNE31x9NU?feature=share","caption":"Dear {{contact.name}} Watch this video about our clinic!","targetPosition":"top","sourcePosition":"bottom"},"width":350,"height":250},{"id":"node_XQ5n4u_HlsfTFQgvXQhFJ","type":"image","position":{"x":765.9125829079687,"y":496.72650535589867},"data":{"label":"Image Node","mediaUrl":"https://i.ibb.co/Xrp4bMDX/dental-Clinic.jpg","caption":"Dear {{contact.name}} Check out our Dental clinic image!","originalName":"","mimetype":"","size":0},"width":350,"height":330}]$dn$::jsonb,
  $de$[{"id":"edge-trigger-node-node_G0dncsqmYeR0luHedcn_m","source":"trigger-node","target":"node_G0dncsqmYeR0luHedcn_m","animated":true,"type":"smoothstep"},{"animated":true,"type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_G0dncsqmYeR0luHedcn_m","sourceHandle":"task_1771362429898_3612","target":"node_-XubJUXAHY9KafiHR_0bd","targetHandle":null,"id":"reactflow__edge-node_G0dncsqmYeR0luHedcn_mtask_1771362429898_3612-node_-XubJUXAHY9KafiHR_0bd"},{"animated":true,"type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_G0dncsqmYeR0luHedcn_m","sourceHandle":"task_1771363045318_9244","target":"node_XQ5n4u_HlsfTFQgvXQhFJ","targetHandle":null,"id":"reactflow__edge-node_G0dncsqmYeR0luHedcn_mtask_1771363045318_9244-node_XQ5n4u_HlsfTFQgvXQhFJ"}]$de$::jsonb,
  ARRAY['whatsapp', 'healthcare', 'dental_clinic'],
  true
)
ON CONFLICT DO NOTHING;

INSERT INTO flow_templates (name, description, category, business_type, nodes, edges, tags, is_active)
VALUES (
  'Salon — Client Journey',
  'End-to-end WhatsApp flow for salons: welcome, service booking, stylist availability, treatment recommendations, and agent handoff.',
  'Beauty',
  'salon',
  $sn$[{"id":"trigger-node-salon","type":"trigger","position":{"x":-317.53423307367075,"y":501.4353816744428},"data":{"label":"Message Trigger","channelTypes":["whatsapp_unofficial"],"conditionType":"any","conditionValue":"","sessionTimeout":30,"sourcePosition":"bottom","targetPosition":"top","sessionTimeoutUnit":"minutes","enableSessionPersistence":true},"width":300,"height":135},{"id":"node_ai_salon","type":"ai_assistant","position":{"x":100,"y":480},"data":{"label":"AI Assistant","model":"gpt-3.5-turbo","tasks":[{"id":"task_salon_video","name":"Share Salon Video","enabled":true,"description":"","outputHandle":"task_salon_video","functionDefinition":{"name":"share_salon_video","parameters":{"type":"object","required":["video_type","user_request"],"properties":{"video_type":{"type":"string","description":"Type of video requested"},"user_request":{"type":"string","description":"The user's request"}}},"description":"Only execute when the user asks for a video about the salon, services, or tutorials."}},{"id":"task_salon_photo","name":"Share Salon Photo","enabled":true,"description":"","outputHandle":"task_salon_photo","functionDefinition":{"name":"share_salon_photo","parameters":{"type":"object","required":["image_type","user_request"],"properties":{"image_type":{"type":"string","description":"Type of image requested"},"user_request":{"type":"string","description":"The user's request"}}},"description":"Trigger when the user asks for an image, photo, or picture of the salon or services."}},{"id":"task_1771371233597_6209","name":"Escalate to Human Agent","description":"","functionDefinition":{"name":"escalate_to_human_agent","description":"Execute this function when the user requests human support or shows frustration. Confirm if they want to talk to a human before escalation.","parameters":{"type":"object","properties":{"reason":{"type":"string","description":"Reason for escalation"},"user_message":{"type":"string","description":"The user's message that triggered escalation"}},"required":["reason"]}},"outputHandle":"task_1771371233597_6209","enabled":true}],"prompt":"You are a helpful *salon assistant*. Answer client queries clearly, politely, and accurately.\n\nYou can help clients with:\n\n* Booking salon appointments (hair, nails, beauty treatments, etc.)\n* Checking stylist and slot availability\n* Service menu and treatment recommendations\n* Pricing and promotions\n* Rescheduling or cancelling appointments\n\nFor appointment booking:\n\n1. Always check available slots first\n2. Collect required details (client name, service type, date, preferred time, phone number)\n3. Confirm all details before booking\n4. Provide a clear confirmation with appointment details\n\nFor rescheduling or cancellation:\n\n* Verify client identity (phone) before making any changes\n* Confirm the requested changes before updating\n\nGuidelines:\n\n* Be friendly, professional, and guide clients to book or find the perfect service\n* Keep responses concise and easy to understand\n* Suggest suitable times if the requested slot is unavailable\n* Do not make up availability; always check slots before responding.\n\nNote: Always check available slots before responding to appointment requests.\n","language":"en","provider":"openai","ttsVoice":"shimmer","_handleKey":1,"mcpServers":[],"enableAudio":false,"stopKeyword":"stop","ttsProvider":"openai","historyLimit":5,"enableHistory":true,"sourcePosition":"bottom","targetPosition":"top","calendarTimeZone":"Asia/Karachi","credentialSource":"auto","enableMCPServers":false,"exitOutputHandle":"ai-stopped","maxAudioDuration":30,"calendarFunctions":[],"voiceResponseMode":"voice_only","enableTextToSpeech":true,"enableZohoCalendar":false,"enableTaskExecution":true,"calendarAdvancedMode":true,"enableGoogleCalendar":true,"knowledgeBaseEnabled":false,"zohoCalendarTimeZone":"Asia/Karachi","calendarBufferMinutes":0,"calendarBusinessHours":{"end":"17:00","start":"09:00"},"enableSessionTakeover":true,"zohoCalendarFunctions":