nLabsStyle":0,"elevenLabsUseSpeakerBoost":true,"elevenLabsPromptInfluence":0.5,"elevenLabsEnableAudioTags":false,"elevenLabsAudioTagsInstructions":"Use [excited] when discussing features, [whispers] for confidential information, [pause] before important points"},"width":511,"height":176},{"id":"node_video_salon","type":"video","position":{"x":764,"y":221},"data":{"label":"Video Node","caption":"Dear {{contact.name}} Check out our salon!","mediaUrl":"","sourcePosition":"bottom","targetPosition":"top"},"width":350,"height":209},{"id":"node_image_salon","type":"image","position":{"x":765,"y":496},"data":{"size":0,"label":"Image Node","caption":"Dear {{contact.name}} Here's a look at our salon!","mediaUrl":"https://i.ibb.co/GN0qp48/Screenshot-2026-02-18-041335.jpg","mimetype":"","originalName":""},"width":350,"height":330},{"id":"node_uEyIXrViw-MA_OR4JTDCH","type":"bot_disable","position":{"x":432.6870682153967,"y":701.0221411449359},"data":{"label":"Bot_disable Node","disableDuration":"30","customDuration":60,"customDurationUnit":"minutes","triggerMethod":"always","keyword":"agent","caseSensitive":false,"assignToAgent":"auto","notifyAgent":true,"handoffMessage":"A customer is requesting human assistance."},"width":316,"height":125}]$sn$::jsonb,
  $se$[{"id":"edge-trigger-ai-salon","type":"smoothstep","source":"trigger-node-salon","target":"node_ai_salon","animated":true},{"id":"edge-ai-video-salon","type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_ai_salon","target":"node_video_salon","animated":true,"sourceHandle":"task_salon_video","targetHandle":null},{"id":"edge-ai-image-salon","type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_ai_salon","target":"node_image_salon","animated":true,"sourceHandle":"task_salon_photo","targetHandle":null},{"id":"reactflow__edge-node_ai_salontask_1771371233597_6209-node_uEyIXrViw-MA_OR4JTDCH","animated":true,"type":"smoothstep","style":{"stroke":"hsl(var(--muted-foreground))"},"source":"node_ai_salon","sourceHandle":"task_1771371233597_6209","target":"node_uEyIXrViw-MA_OR4JTDCH","targetHandle":null}]$se$::jsonb,
