INSERT INTO flow_templates (name, description, category, business_type, nodes, edges, tags, is_active)
VALUES (
  'Real Estate Flow',
  'End-to-end WhatsApp flow for real estate: property search, listing details, viewing scheduling, valuations, and agent handoff.',
